// 伪代码：DMA 双缓冲 UART 接收架构
// 架构示意，非可直接编译

typedef struct {
    uint8_t buf[128];
    volatile uint16_t len;       // 已填充长度
    volatile bool   ready;       // 缓冲区是否可读
    volatile bool   dirty;       // 是否被 DMA 覆盖
} dma_buf_t;

static dma_buf_t g_bufs[2] = {
    { .buf = {0}, .len = 0, .ready = false, .dirty = false },
    { .buf = {0}, .len = 0, .ready = false, .dirty = false }
};

static volatile uint8_t g_active = 0;  // 0=BufA, 1=BufB

// HAL 回调：DMA 半传输中断（BufA 已填满 64 字节）
void HAL_DMA HalfTransferCallback(DMA_HandleTypeDef *hdma) {
    // 硬件动作：DMA_SxCR_HTIE 置位，DMA 已将数据搬至 BufA[0..63]
    // ISR 只做一件事：标记半传输完成，不做数据处理
    g_bufs[g_active].len = 64;
    g_bufs[g_active].ready = true;
    g_bufs[g_active].dirty = false;
    // 下一步：切换目标到 BufB，DMA 开始填 BufB
    g_active = 1 - g_active;
}

// HAL 回调：DMA 全传输中断（当前缓冲区已填满 128 字节）
void HAL_DMA TransferCpltCallback(DMA_HandleTypeDef *hdma) {
    g_bufs[g_active].len = 128;
    g_bufs[g_active].ready = true;
    g_bufs[g_active].dirty = false;
    g_active = 1 - g_active;
}

// 应用层：dequeue 已完成的缓冲区
// 返回: >0=读取字节数, -1=无数据, -2=缓冲区被覆盖(丢失数据)
int dequeue_dma_buf(uint8_t *out, uint16_t maxlen) {
    for (int i = 0; i < 2; i++) {
        if (!g_bufs[i].ready) continue;
        // 检查缓冲区是否被 DMA 静默覆盖（应用层太慢）
        if (g_bufs[i].dirty) {
            g_bufs[i].ready = false;
            g_bufs[i].len = 0;
            return -2;  // 数据丢失
        }
        uint16_t avail = g_bufs[i].len;
        uint16_t copy = (avail < maxlen) ? avail : maxlen;
        memcpy(out, g_bufs[i].buf, copy);
        g_bufs[i].ready = false;
        g_bufs[i].dirty = true;  // 标记为应用层持有中
        return copy;
    }
    return -1;  // 无数据
}

/* dma_uart_ring.c — DMA + UART 循环缓冲区初始化 */
/* 平台: STM32F407, 时钟: 168MHz, UART1 @ 115200 8-N-1 */

#define UART_RX_BUF_SIZE  256U

static uint8_t uart_rx_buf[UART_RX_BUF_SIZE];  /* 循环缓冲区 */
static uint16_t rx_write_idx = 0;               /* DMA 写入索引 */
static uint16_t rx_read_idx  = 0;               /* 应用层读取索引 */

/* DMA2 Stream5, Channel 4 for USART1_RX */
static DMA_HandleTypeDef hdma_usart1_rx;

static void dma_uart_init(void) {
    /* 1. 使能 UART1 和 DMA2 时钟 */
    __HAL_RCC_USART1_CLK_ENABLE();    /* USART1 挂在 APB2 */
    __HAL_RCC_DMA2_CLK_ENABLE();      /* DMA2 在 AHB1 */

    /* 2. 配置 GPIOA9 = TX, GPIOA10 = RX */
    __HAL_RCC_GPIOA_CLK_ENABLE();
    GPIO_InitTypeDef gpio = {
        .Pin = GPIO_PIN_9 | GPIO_PIN_10,
        .Mode = GPIO_MODE_AF_PP,    /* TX 推挽复用 */
        .Pull = GPIO_PULLUP,         /* RX 上拉 */
        .Speed = GPIO_SPEED_FREQ_VERY_HIGH,
        .Alternate = GPIO_AF7_USART1
    };
    HAL_GPIO_Init(GPIOA, &gpio);

    /* 3. 配置 UART1: 115200, 8N1, 无硬件流控 */
    USART_InitTypeDef uart = {
        .BaudRate = 115200,
        .WordLength = USART_WORDLENGTH_8B,
        .StopBits = USART_STOPBITS_1,
        .Parity = USART_PARITY_NONE,
        .Mode = USART_MODE_RX | USART_MODE_TX,
        .HwFlowCtl = USART_HWCONTROL_NONE
    };
    HAL_UART_Init(&huart1);

    /* 4. 配置 DMA2 Stream5 for USART1 Rx */
    hdma_usart1_rx.Instance = DMA2_Stream5;
    hdma_usart1_rx.Init.Channel    = DMA_CHANNEL_4;   /* USART1 对应 Channel 4 */
    hdma_usart1_rx.Init.Direction  = DMA_PERIPH_TO_MEMORY;  /* UART→RAM */
    hdma_usart1_rx.Init.PeriphInc  = DMA_PINC_DISABLE;      /* 外设地址固定 */
    hdma_usart1_rx.Init.MemInc     = DMA_MINC_ENABLE;        /* 内存地址递增 */
    hdma_usart1_rx.Init.PeriphDataAlignment = DMA_PDATAALIGN_BYTE;
    hdma_usart1_rx.Init.MemDataAlignment    = DMA_MDATAALIGN_BYTE;
    hdma_usart1_rx.Init.Mode      = DMA_CIRCULAR;  /* 循环模式：到末尾回到起始 */
    hdma_usart1_rx.Init.Priority  = DMA_PRIORITY_HIGH; /* 高优先级 */
    HAL_DMA_Init(&hdma_usart1_rx);

    /* 5. 关联 DMA 到 UART1 Rx */
    __HAL_LINKDMA(&huart1, hdmarx, hdma_usart1_rx);

    /* 6. 配置 NVIC: DMA 抢占优先级 1, UART1 全局中断优先级 2 */
    /* DMA 优先于 UART 全局中断，防止搬运冲突 */
    NVIC_SetPriority(DMA2_Stream5_IRQn, NVIC_EncodePriority(NVIC_GetPriorityGrouping(), 1, 0));
    NVIC_SetPriority(USART1_IRQn, NVIC_EncodePriority(NVIC_GetPriorityGrouping(), 2, 0));
    NVIC_EnableIRQ(DMA2_Stream5_IRQn);
    NVIC_EnableIRQ(USART1_IRQn);

    /* 7. 启动 DMA 循环接收 — 注意：HAL 的 MultiBuffer 模式 */
    HAL_DMAEx_MultiBufferStart(&hdma_usart1_rx, (uint32_t)&uart_rx_buf,
                               (uint32_t)uart_rx_buf, UART_RX_BUF_SIZE / 2);

    /* 8. 启动 UART DMA 接收 */
    HAL_UART_Receive_DMA(&huart1, uart_rx_buf, UART_RX_BUF_SIZE / 2);
    /* 此时 DMA SxCR 的 EN 位被置 1，DMA 开始从 UART_DR 搬运数据到 uart_rx_buf */
}

/* 应用层：从环形缓冲区读取数据 */
/* 返回: 读取的字节数, 0=无数据 */
uint16_t dma_uart_read(uint8_t *out, uint16_t maxlen) {
    uint16_t available;
    /* 计算环形缓冲区中可用数据量 */
    if (rx_write_idx >= rx_read_idx) {
        available = rx_write_idx - rx_read_idx;
    } else {
        available = (UART_RX_BUF_SIZE - rx_read_idx) + rx_write_idx;
    }
    if (available == 0) return 0;

    uint16_t copy = (maxlen < available) ? maxlen : available;

    /* 处理环形边界：可能需要两次 memcpy */
    uint16_t first_chunk = (UART_RX_BUF_SIZE - rx_read_idx);
    if (copy <= first_chunk) {
        /* 数据在同一连续段 */
        memcpy(out, &uart_rx_buf[rx_read_idx], copy);
    } else {
        /* 跨越缓冲区末尾 */
        memcpy(out, &uart_rx_buf[rx_read_idx], first_chunk);
        memcpy(&out[first_chunk], uart_rx_buf, copy - first_chunk);
    }

    rx_read_idx = (rx_read_idx + copy) % UART_RX_BUF_SIZE;
    return copy;
}

/* 陷阱 3 的代码演示：volatile 缺失导致 HardFault */

/* ❌ 错误写法：rx_write_idx 缺少 volatile */
static uint16_t rx_write_idx = 0;    /* 编译器可能将其缓存到 R0 寄存器 */
static uint16_t rx_read_idx  = 0;

/* DMA 回调中更新索引 */
void HAL_DMA TransferCpltCallback(DMA_HandleTypeDef *hdma) {
    rx_write_idx += 128;  /* 写的是 R0，主循环可能看不到 */
    if (rx_write_idx >= UART_RX_BUF_SIZE)
        rx_write_idx -= UART_RX_BUF_SIZE;
}

/* 主循环中读取 — 编译器优化后永远读到旧的 rx_write_idx 值 */
void main_loop(void) {
    while (1) {
        uint16_t avail = rx_write_idx - rx_read_idx;  /* 永远相等！ */
        if (avail > 0) {
            /* 永远不会进入这里，因为编译器缓存了 rx_write_idx */
            uint8_t buf[128];
            dma_uart_read(buf, avail);
            process_data(buf, avail);
        }
    }
}

/* ✅ 正确写法：加上 volatile，强制每次从内存读取 */
static volatile uint16_t rx_write_idx = 0;  /* 每次访问都读内存 */
static volatile uint16_t rx_read_idx  = 0;

/* 更好的方案：用原子操作（如果有 Cortex-M7 的 LDREX/STREX）*/
static inline void atomic_inc(volatile uint16_t *ptr, uint16_t val) {
    __disable_irq();
    *ptr += val;
    if (*ptr >= UART_RX_BUF_SIZE)
        *ptr -= UART_RX_BUF_SIZE;
    __enable_irq();
}

void HAL_DMA TransferCpltCallback(DMA_HandleTypeDef *hdma) {
    atomic_inc(&rx_write_idx, 128);
}

/* ============ 重构前：轮询 UART 接收（坏味道代码） ============ */

/* 问题 1: 没有封装，所有逻辑散落在 main.c 中 */
/* 问题 2: 只能处理一个 UART，加第二个就要复制粘贴 */
/* 问题 3: 阻塞等待——等不到字节就卡死 */

/* main.c — 重构前 */
void main(void) {
    HAL_Init();
    SystemClock_Config();
    MX_USART1_UART_Init();

    while (1) {
        uint8_t byte;
        /* 阻塞等待：如果 UART 没数据，主循环就卡在这里 */
        if (HAL_UART_Receive(&huart1, &byte, 1, 100) == HAL_OK) {
            /* 收到一字节，但无法处理更多——一次只收一个 */
            if (byte == 0xAA) {
                /* 帧头匹配，继续接收剩余数据 */
                uint8_t frame[32];
                frame[0] = byte;
                for (uint8_t i = 1; i < 32; i++) {
                    /* 又一个阻塞等待！如果发送方中断，整个循环卡死 */
                    if (HAL_UART_Receive(&huart1, &frame[i], 1, 10) == HAL_OK) {
                        process_frame(frame, i + 1);
                    }
                }
            }
        }
        /* 主循环其他工作被严重挤压 */
        blink_led();
    }
}

/* ============ 重构后：DMA + 环形缓冲区封装 ============ */

/* uart_ring.h — 模块接口 */
typedef struct {
    UART_HandleTypeDef *huart;       /* 关联的 UART 句柄 */
    uint8_t            *buf;         /* 环形缓冲区指针 */
    uint16_t            buf_size;    /* 缓冲区大小 */
    volatile uint16_t   write_idx;   /* DMA 写入索引 */
    volatile uint16_t   read_idx;    /* 应用层读取索引 */
    volatile bool       running;     /* DMA 接收是否活跃 */
} uart_ring_buf_t;

/* 模块 API */
void    uart_ring_init(uart_ring_buf_t *ring, UART_HandleTypeDef *huart,
                       uint8_t *buf, uint16_t buf_size);
uint16_t uart_ring_read(uart_ring_buf_t *ring, uint8_t *out, uint16_t maxlen);
bool     uart_ring_ready(uart_ring_buf_t *ring);  /* 是否有数据可读 */

/* uart_ring.c — 模块实现 */
void uart_ring_init(uart_ring_buf_t *ring, UART_HandleTypeDef *huart,
                    uint8_t *buf, uint16_t buf_size) {
    ring->huart = huart;
    ring->buf = buf;
    ring->buf_size = buf_size;
    ring->write_idx = 0;
    ring->read_idx = 0;
    ring->running = false;

    /* 启动 DMA 循环接收 */
    HAL_UART_Receive_DMA(huart, buf, buf_size);
    ring->running = true;
}

uint16_t uart_ring_read(uart_ring_buf_t *ring, uint8_t *out, uint16_t maxlen) {
    uint16_t write = ring->write_idx;
    uint16_t read  = ring->read_idx;
    uint16_t avail;

    if (write >= read) {
        avail = write - read;
    } else {
        avail = (ring->buf_size - read) + write;
    }
    if (avail == 0) return 0;

    uint16_t copy = (maxlen < avail) ? maxlen : avail;
    uint16_t first_chunk = (ring->buf_size - read);

    if (copy <= first_chunk) {
        memcpy(out, &ring->buf[read], copy);
    } else {
        memcpy(out, &ring->buf[read], first_chunk);
        memcpy(&out[first_chunk], ring->buf, copy - first_chunk);
    }
    ring->read_idx = (read + copy) % ring->buf_size;
    return copy;
}

/* 主循环 — 重构后 */
/* DMA 回调中更新 write_idx */
void HAL_UART RxCpltCallback(UART_HandleTypeDef *huart) {
    /* 找到对应的 ring 实例，更新 write_idx */
    /* 实际项目中用链表或数组管理多个 ring 实例 */
    uart1_ring.write_idx = (uart1_ring.write_idx + UART_RX_BUF_SIZE) % UART_RX_BUF_SIZE;
}

void main(void) {
    HAL_Init();
    SystemClock_Config();
    MX_USART1_UART_Init();
    MX_USART2_UART_Init();

    /* 两个 UART 实例，同一套 API — 零重复代码 */
    uint8_t rx_buf1[UART_RX_BUF_SIZE];
    uint8_t rx_buf2[UART_RX_BUF_SIZE];
    uart_ring_init(&uart1_ring, &huart1, rx_buf1, UART_RX_BUF_SIZE);
    uart_ring_init(&uart2_ring, &huart2, rx_buf2, UART_RX_BUF_SIZE);

    uint8_t frame_buf[256];

    while (1) {
        /* UART1: 非阻塞读取 */
        uint16_t len = uart_ring_read(&uart1_ring, frame_buf, sizeof(frame_buf));
        if (len > 0) {
            process_frame(frame_buf, len);  /* 处理完整帧 */
        }

        /* UART2: 同样非阻塞 */
        len = uart_ring_read(&uart2_ring, frame_buf, sizeof(frame_buf));
        if (len > 0) {
            process_gps_frame(frame_buf, len);
        }

        /* 主循环其他工作正常执行 */
        blink_led();
        update_display();
        check_buttons();
    }
}
